mapper.select:
SELECT COUNT(*) FROM product_comment pc LEFT JOIN product p ON pc.product_id = p.id LEFT JOIN user u ON pc.user_id = u.id
AND (u.username LIKE CONCAT('%', #{keyword}, '%') OR pc.content LIKE CONCAT('%', #{keyword}, '%') OR p.name LIKE CONCAT('%', #{keyword}, '%'))
AND pc.rating = #{rating}
AND pc.status = #{status}
AND (pc.reply IS NULL OR pc.reply = '')
AND pc.reply IS NOT NULL AND pc.reply != ''

SELECT c.id, c.product_id, c.user_id, c.order_no, c.rating, c.content, c.images, c.reply, c.reply_time, c.status, c.create_time, p.name as product_name, u.username as user_name, u.nickname as user_nickname, u.avatar as user_avatar FROM product_comment c LEFT JOIN product p ON c.product_id = p.id LEFT JOIN user u ON c.user_id = u.id WHERE c.product_id = #{productId} AND c.status = 1
AND c.rating = #{rating}
ORDER BY c.create_time DESC LIMIT #{offset}, #{limit}
